import React, { useState, useEffect } from 'react';
import styled, { keyframes } from 'styled-components';
import { 
  BarChart3, 
  Users, 
  Code, 
  Database, 
  Cloud, 
  Rocket, 
  AlertCircle, 
  CheckCircle, 
  Clock, 
  Zap,
  TrendingUp,
  DollarSign,
  GitBranch,
  Server,
  HardDrive,
  MessageSquare,
  // Adding more icons for enhanced UI
  Plus,
  Eye,
  EyeOff,
  Trash2,
  Copy,
  Share2,
  Heart,
  ThumbsUp,
  ThumbsDown,
  Search,
  Filter,
  Grid,
  List,
  ExternalLink,
  Play,
  Square,
  RefreshCw,
  Settings,
  Edit3,
  Image,
  Monitor,
  Smartphone,
  Tablet,
  Globe,
  Download,
  Link,
  // Additional icons for AI Studio-like experience
  FileCode,
  FileText as FileDocument,
  ImageIcon,
  Video,
  Music,
  Calendar,
  MapPin,
  Mail,
  Phone,
  Link as LinkIcon
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

// Consistent color palette and styling across all components
const theme = {
  primaryGradient: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
  secondaryGradient: 'linear-gradient(135deg, #f0f9ff 0%, #e0f2fe 100%)',
  successGradient: 'linear-gradient(135deg, #f0fdf4 0%, #dcfce7 100%)',
  cardBackground: 'white',
  borderColor: '#e2e8f0',
  boxShadow: '0 4px 15px rgba(0, 0, 0, 0.05)',
