    navigate('/builder');
  };

  const handleViewDemo = (project) => {
    if (project.previewUrl) {
      window.open(project.previewUrl, '_blank');
    } else {
      // In a real implementation, this would show a preview modal or message
      alert('Demo not available for this project yet.');
    }
  };

  const handleViewProject = (project) => {
    setSelectedProject(project);
    setShowProjectModal(true);
  };

  const handleDeployProject = (projectId) => {
    navigate('/deploy');
  };

  const handleDeleteProject = (projectId) => {
    if (window.confirm('Are you sure you want to delete this project?')) {
      setProjects(prev => prev.filter(project => project.id !== projectId));
    }
  };

  const handleEditProject = (projectId) => {
    // In a real implementation, this would navigate to the project edit page
    console.log(`Editing project ${projectId}`);
  };

  const handleGenerateProject = () => {
    navigate('/builder');
  };

  const getStatusText = (status) => {
    switch (status) {
      case 'completed':
        return 'Completed';
      case 'in-progress':
        return 'In Progress';
      case 'failed':
        return 'Failed';
      default:
        return 'Unknown';
    }
  };

  const quickActions = [
    {
      title: 'New Project',
      description: 'Create a new application from scratch',
      icon: Plus,
      action: handleCreateNew
    },
    {
      title: 'AI Chat',
      description: 'Chat with AI to build applications',
      icon: MessageSquare,
      action: () => navigate('/ai-chat')
    },
    {
      title: 'Deploy',
      description: 'Deploy your applications to the cloud',
      icon: Rocket,
      action: () => navigate('/deploy')
    },
    {
      title: 'Integrations',
      description: 'Connect third-party services',
      icon: GitBranch,
      action: () => navigate('/integrations')
    }
  ];

  return (
    <Container>
      <Header>
        <Title>Dashboard</Title>
        <Subtitle>Welcome back! Here's what's happening with your projects.</Subtitle>
      </Header>
      
      <StatsGrid>
        <StatCard>
          <StatHeader>
            <StatTitle>Total Projects</StatTitle>
            <StatIcon>
              <Code size={20} />
            </StatIcon>
          </StatHeader>
          <StatValue>{stats.totalProjects}</StatValue>
          <StatChange className="positive">
            <TrendingUp size={16} />
            12% from last month
          </StatChange>
        </StatCard>
        
        <StatCard>
          <StatHeader>
            <StatTitle>Active Projects</StatTitle>
            <StatIcon>
              <Zap size={20} />
            </StatIcon>
          </StatHeader>
          <StatValue>{stats.activeProjects}</StatValue>
          <StatChange className="positive">
            <TrendingUp size={16} />
            5% from last month
          </StatChange>
        </StatCard>
        
        <StatCard>
          <StatHeader>
            <StatTitle>Completed</StatTitle>
            <StatIcon>
              <CheckCircle size={20} />
            </StatIcon>
          </StatHeader>
          <StatValue>{stats.completedProjects}</StatValue>
          <StatChange className="positive">
            <TrendingUp size={16} />
            8% from last month
          </StatChange>
        </StatCard>
        
        <StatCard>
          <StatHeader>
            <StatTitle>Deployments</StatTitle>
            <StatIcon>
              <Rocket size={20} />
            </StatIcon>
          </StatHeader>
          <StatValue>{stats.totalDeployments}</StatValue>
          <StatChange className="positive">
            <TrendingUp size={16} />
            15% from last month
          </StatChange>
        </StatCard>
      </StatsGrid>
      
      <Section>
        <SectionHeader>
          <SectionTitle>Quick Actions</SectionTitle>
        </SectionHeader>
        
        <QuickActions>
          {quickActions.map((action, index) => (
            <ActionCard key={index} onClick={action.action}>
              <ActionIcon>
                <action.icon size={24} />
              </ActionIcon>
              <ActionTitle>{action.title}</ActionTitle>
              <ActionDescription>{action.description}</ActionDescription>
            </ActionCard>
          ))}
        </QuickActions>
      </Section>
      
      <Section>
        <SectionHeader>
          <SectionTitle>Your Projects</SectionTitle>
          <Controls>
            <SearchInput
              type="text"
              placeholder="Search projects..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <FilterButton onClick={() => setFilterStatus(filterStatus === 'all' ? 'completed' : 'all')}>
              <Filter size={16} />
              {filterStatus === 'all' ? 'Show Completed' : 'Show All'}
            </FilterButton>
            <ViewToggle>
              <ViewButton 
                active={viewMode === 'list'} 
                onClick={() => setViewMode('list')}
              >
                <List size={16} />
                List
              </ViewButton>
              <ViewButton 
                active={viewMode === 'grid'} 
                onClick={() => setViewMode('grid')}
              >
                <Grid size={16} />
                Grid
              </ViewButton>
            </ViewToggle>
            <ViewAllButton onClick={handleCreateNew}>
              <Plus size={16} />
              New Project
            </ViewAllButton>
          </Controls>
        </SectionHeader>
        
        {viewMode === 'list' ? (
          <ProjectList>
            {filteredProjects.map(project => (
              <ProjectItem key={project.id}>
                <ProjectIcon>
                  <Code size={20} />
                </ProjectIcon>
                <ProjectInfo>
                  <ProjectName>{project.name}</ProjectName>
                  <ProjectMeta>
                    <span>{project.framework}</span>
                    <span>Created: {project.createdAt}</span>
                    <span>Modified: {project.lastModified}</span>
                  </ProjectMeta>
                </ProjectInfo>
                <ProjectActions>
                  <StatusIndicator className={project.status}>
                    {getStatusText(project.status)}
                  </StatusIndicator>
                  <ActionButton onClick={() => handleViewProject(project)}>
                    <Eye size={16} />
                    View
                  </ActionButton>
                  {project.previewUrl && (
                    <ActionButton 
                      className="success" 
                      onClick={() => handleViewDemo(project)}
                    >
                      <ExternalLink size={16} />
                      Demo
                    </ActionButton>
                  )}
                  {!project.deployed && (
                    <ActionButton 
                      className="primary" 
                      onClick={() => handleDeployProject(project.id)}
                    >
                      <Rocket size={16} />
                      Deploy
                    </ActionButton>
                  )}
                  <ActionButton onClick={() => handleEditProject(project.id)}>
                    <Edit3 size={16} />
                    Edit
                  </ActionButton>
                  <ActionButton 
                    className="danger" 
                    onClick={() => handleDeleteProject(project.id)}
                  >
                    <Trash2 size={16} />
                    Delete
                  </ActionButton>
                </ProjectActions>
              </ProjectItem>
            ))}
          </ProjectList>
        ) : (
          <ProjectGrid>
            {filteredProjects.map(project => (
              <ProjectCard key={project.id}>
                <ProjectHeader>
                  <div>
                    <ProjectTitle>{project.name}</ProjectTitle>
                    <ProjectFramework>{project.framework}</ProjectFramework>
                  </div>
                  <StatusIndicator className={project.status}>
                    {getStatusText(project.status)}
                  </StatusIndicator>
                </ProjectHeader>
                
                <ProjectDetails>
                  <ProjectDetail>
                    <span className="label">Created</span>
                    <span className="value">{project.createdAt}</span>
                  </ProjectDetail>
                  <ProjectDetail>
                    <span className="label">Last Modified</span>
                    <span className="value">{project.lastModified}</span>
                  </ProjectDetail>
                  <ProjectDetail>
                    <span className="label">Features</span>
                    <span className="value">{project.features.join(', ')}</span>
                  </ProjectDetail>
                  <ProjectDetail>
                    <span className="label">Tech Stack</span>
                    <span className="value">
                      {project.techStack.frontend} + {project.techStack.backend} + {project.techStack.database}
                    </span>
                  </ProjectDetail>
                </ProjectDetails>
                
                <TechStack>
                  {Object.values(project.techStack).map((tech, index) => (
                    <TechTag key={index}>{tech}</TechTag>
                  ))}
                </TechStack>
                
                <FeaturesList>
                  {project.features.slice(0, 3).map((feature, index) => (
                    <FeatureTag key={index}>{feature}</FeatureTag>
                  ))}
                  {project.features.length > 3 && (
                    <FeatureTag>+{project.features.length - 3} more</FeatureTag>
                  )}
                </FeaturesList>
                
                {project.previewUrl && (
                  <DemoPreview>
                    <DemoImage>
                      <Globe size={40} />
                    </DemoImage>
                    <DemoOverlay>
                      <DemoActions>
                        <DemoButton onClick={() => handleViewDemo(project)}>
                          <ExternalLink size={16} />
                          View Demo
                        </DemoButton>
                      </DemoActions>
                    </DemoOverlay>
                  </DemoPreview>
                )}
                
                <ProjectActionsGrid>
                  <ActionButton onClick={() => handleViewProject(project)}>
                    <Eye size={16} />
                    View
                  </ActionButton>
                  {project.previewUrl ? (
                    <ActionButton 
                      className="success" 
                      onClick={() => handleViewDemo(project)}
                    >
                      <ExternalLink size={16} />
                      Demo
                    </ActionButton>
                  ) : (
                    <ActionButton disabled>
                      <ExternalLink size={16} />
                      No Demo
                    </ActionButton>
                  )}
                  {!project.deployed && (
                    <ActionButton 
                      className="primary" 
                      onClick={() => handleDeployProject(project.id)}
                    >
                      <Rocket size={16} />
                      Deploy
                    </ActionButton>
                  )}
                  <ActionButton 
                    className="danger" 
                    onClick={() => handleDeleteProject(project.id)}
                  >
                    <Trash2 size={16} />
                    Delete
                  </ActionButton>
                </ProjectActionsGrid>
              </ProjectCard>
            ))}
          </ProjectGrid>
        )}
      </Section>
      
      {showProjectModal && selectedProject && (
        <ModalOverlay onClick={() => setShowProjectModal(false)}>
          <ModalContent onClick={(e) => e.stopPropagation()}>
            <ModalHeader>
              <ModalTitle>{selectedProject.name}</ModalTitle>
              <CloseButton onClick={() => setShowProjectModal(false)}>
                <X size={20} />
              </CloseButton>
            </ModalHeader>
            <ModalBody>
              <ProjectDetailsSection>
                <ProjectDetailsTitle>
                  <FileDocument size={20} />
                  Project Details
                </ProjectDetailsTitle>
                <ProjectDetailsGrid>
                  <ProjectDetailCard>
                    <ProjectDetailLabel>Status</ProjectDetailLabel>
                    <ProjectDetailValue>
                      <StatusIndicator className={selectedProject.status}>
                        {getStatusText(selectedProject.status)}
                      </StatusIndicator>
                    </ProjectDetailValue>
                  </ProjectDetailCard>
                  
                  <ProjectDetailCard>
                    <ProjectDetailLabel>Framework</ProjectDetailLabel>
                    <ProjectDetailValue>{selectedProject.framework}</ProjectDetailValue>
                  </ProjectDetailCard>
                  
                  <ProjectDetailCard>
                    <ProjectDetailLabel>Created</ProjectDetailLabel>
                    <ProjectDetailValue>{selectedProject.createdAt}</ProjectDetailValue>
                  </ProjectDetailCard>
                  
                  <ProjectDetailCard>
                    <ProjectDetailLabel>Last Modified</ProjectDetailLabel>
                    <ProjectDetailValue>{selectedProject.lastModified}</ProjectDetailValue>
                  </ProjectDetailCard>
                </ProjectDetailsGrid>
              </ProjectDetailsSection>
              
              <ProjectDetailsSection>
                <ProjectDetailsTitle>
                  <Code size={20} />
                  Tech Stack
                </ProjectDetailsTitle>
                <TechStack>
                  {Object.values(selectedProject.techStack).map((tech, index) => (
                    <TechTag key={index}>{tech}</TechTag>
                  ))}
                </TechStack>
              </ProjectDetailsSection>
              
              <ProjectDetailsSection>
                <ProjectDetailsTitle>
                  <Star size={20} />
                  Features
                </ProjectDetailsTitle>
                <FeaturesList>
                  {selectedProject.features.map((feature, index) => (
                    <FeatureTag key={index}>{feature}</FeatureTag>
                  ))}
                </FeaturesList>
              </ProjectDetailsSection>
              
              <ProjectDetailsSection>
                <ProjectDetailsTitle>
                  <Monitor size={20} />
                  Application Preview
                </ProjectDetailsTitle>
                {selectedProject.previewUrl ? (
                  <ModalDemoPreview>
                    <ModalDemoImage>
                      <Globe size={60} />
                    </ModalDemoImage>
                    <p>This is a preview of your generated application. The full demo shows your complete application with all features.</p>
                    <p>Tech Stack: {selectedProject.techStack.frontend} + {selectedProject.techStack.backend} + {selectedProject.techStack.database}</p>
                  </ModalDemoPreview>
                ) : (
                  <ModalDemoPreview>
                    <ModalDemoImage>
                      <ImageIcon size={60} />
                    </ModalDemoImage>
                    <p>Demo not available for this project yet. Generate a project to see a live preview.</p>
                    <ActionButton 
                      className="primary" 
                      onClick={() => {
                        setShowProjectModal(false);
                        navigate('/builder');
                      }}
                      style={{ marginTop: '1rem' }}
                    >
                      <Plus size={16} />
                      Create New Project
                    </ActionButton>
                  </ModalDemoPreview>
                )}
              </ProjectDetailsSection>
            </ModalBody>
            <ModalActions>
              <ActionButton onClick={() => setShowProjectModal(false)}>
                <X size={16} />
                Close
              </ActionButton>
              {selectedProject.previewUrl && (
                <ActionButton 
                  className="success" 
                  onClick={() => handleViewDemo(selectedProject)}
                >
                  <ExternalLink size={16} />
                  View Demo
                </ActionButton>
              )}
              <ActionButton 
                className="primary" 
                onClick={() => {
                  setShowProjectModal(false);
                  handleEditProject(selectedProject.id);
                }}
              >
                <Edit3 size={16} />
                Edit Project
              </ActionButton>
            </ModalActions>
          </ModalContent>
        </ModalOverlay>
      )}
    </Container>
  );
}

export default Dashboard;
